# -*- coding: utf-8 -*-
# PPPE / biosecurity terms.
GLOSSARY_ADD = [
    {"term": "PPE / PPPE", "defn": "Personal protective equipment. In a grow it is plant and personal: the same gown, gloves and covers protect the crop from the person and the person from hazards.", "tags": ["operations", "health"]},
    {"term": "Gowning / de-gowning", "defn": "Donning and doffing protective clothing in a defined order across a clean/dirty line, so contamination never crosses. Gown top-down; de-gown in reverse, dirtiest first.", "tags": ["operations", "health"]},
    {"term": "Fomite", "defn": "An object that carries and transfers microbes, e.g. a phone, pen, tool or handle. Hands move contamination from fomites to the crop.", "tags": ["health"]},
    {"term": "Bioaerosol", "defn": "Airborne particles carrying living things, such as skin flakes with bacteria, fungal spores, or droplets from speech or a toilet flush.", "tags": ["health"]},
    {"term": "Cross-contamination", "defn": "Carrying contamination from a dirty area or item to a clean one, e.g. walking from flower back into propagation without re-gowning.", "tags": ["operations", "health"]},
    {"term": "Hierarchy of controls", "defn": "The legal order for managing risk: eliminate, substitute, isolate, engineer, administrate, then PPE as the last line.", "tags": ["operations"]},
    {"term": "PCBU", "defn": "Person Conducting a Business or Undertaking, the NZ legal term (Health and Safety at Work Act 2015) for the duty-holding business, i.e. the employer.", "tags": ["operations"]},
]
